<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CGO_ENABLED=0 GOOS=linux go build -trimpath -ldflags=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;-s -w&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -o /out/api ./cmd/api</span></span>
